import{E as e,R as t,_ as n,h as r,pt as i,x as a,z as o}from"./runtime-core.esm-bundler-zlLwmkyI.js";var s={class:`ant-doc vp-doc`},c=a({__name:`llms.en-US`,setup(a,{expose:c}){let l={title:`LLMs.txt`,frontmatter:{title:`LLMs.txt`,tag:`New`},headers:[{level:2,title:`What is LLMs.txt?`,slug:`what-is-llms-txt`,link:`#what-is-llms-txt`,children:[]},{level:2,title:`Available Routes`,slug:`available-routes`,link:`#available-routes`,children:[]},{level:2,title:`Usage with AI Tools`,slug:`usage-with-ai-tools`,link:`#usage-with-ai-tools`,children:[{level:3,title:`Cursor`,slug:`cursor`,link:`#cursor`,children:[]},{level:3,title:`Windsurf`,slug:`windsurf`,link:`#windsurf`,children:[]},{level:3,title:`Claude Code`,slug:`claude-code`,link:`#claude-code`,children:[]},{level:3,title:`Gemini CLI`,slug:`gemini-cli`,link:`#gemini-cli`,children:[]},{level:3,title:`Trae`,slug:`trae`,link:`#trae`,children:[]},{level:3,title:`Qoder`,slug:`qoder`,link:`#qoder`,children:[]},{level:3,title:`Other AI Tools`,slug:`other-ai-tools`,link:`#other-ai-tools`,children:[]}]}],description:``},u={title:`LLMs.txt`,tag:`New`},d=i({});o(`__pageData__`,e=>{d.value=e});let f=e(`__pageData__`,null);return f&&f(l),o(`__pageInfo__`,l),c({frontmatter:u,pageData:l}),(e,i)=>(t(),r(`div`,s,[...i[0]||=[n(`<p>This guide explains how to enable AI tools like Cursor, Windsurf, and Claude to better understand ProComponents of Vue.</p><h2 id="what-is-llms-txt" tabindex="-1">What is LLMs.txt? <a class="header-anchor" href="#what-is-llms-txt" aria-label="Permalink to &quot;What is LLMs.txt?&quot;">​</a></h2><p>We support <a href="https://llmstxt.org/">LLMs.txt</a> files for making the ProComponents of Vuents of Vue documentation available to large language models (LLMs). This feature helps AI tools better understand our component library, its APIs, and usage patterns.</p><h2 id="available-routes" tabindex="-1">Available Routes <a class="header-anchor" href="#available-routes" aria-label="Permalink to &quot;Available Routes&quot;">​</a></h2><p>We provide several LLMs.txt routes to help AI tools access our documentation:</p><ul><li><a href="https://antdv-next.com/llms.txt">llms.txt</a> - Contains a structured overview of all components and their documentation links</li><li><a href="https://antdv-next.com/llms-full.txt">llms-full.txt</a> - Provides comprehensive documentation including implementation details and examples</li></ul><h2 id="usage-with-ai-tools" tabindex="-1">Usage with AI Tools <a class="header-anchor" href="#usage-with-ai-tools" aria-label="Permalink to &quot;Usage with AI Tools&quot;">​</a></h2><h3 id="cursor" tabindex="-1">Cursor <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;Cursor&quot;">​</a></h3><p>Use the <code>@Docs</code> feature in Cursor to include the LLMs.txt files in your project. This helps Cursor provide more accurate code suggestions and documentation for ProComponents of Vuents of Vue components.</p><p><a href="https://docs.cursor.com/context/@-symbols/@-docs">Read more about @Docs in Cursor</a></p><h3 id="windsurf" tabindex="-1">Windsurf <a class="header-anchor" href="#windsurf" aria-label="Permalink to &quot;Windsurf&quot;">​</a></h3><p>Reference the LLMs.txt files using <code>@</code> or in your <code>.windsurf/rules</code> files to enhance Windsurf’s understanding of ProComponents of Vuents of Vue components.</p><p><a href="https://docs.windsurf.com/windsurf/cascade/memories">Read more about Windsurf Memories</a></p><h3 id="claude-code" tabindex="-1">Claude Code <a class="header-anchor" href="#claude-code" aria-label="Permalink to &quot;Claude Code&quot;">​</a></h3><p>In Claude Code, add <code>LLMs.txt</code> to the workspace Knowledge Base (Docs / Context Files) configuration. This allows the file to be referenced during code completion and explanation, improving understanding of ProComponents of Vuents of Vue components.</p><p><a href="https://code.claude.com/docs">Learn more about Claude Code document context configuration</a></p><h3 id="gemini-cli" tabindex="-1">Gemini CLI <a class="header-anchor" href="#gemini-cli" aria-label="Permalink to &quot;Gemini CLI&quot;">​</a></h3><p>In Gemini CLI, you can specify the <code>LLMs.txt</code> file path with the <code>--context</code> parameter or in <code>.gemini/config.json</code>, enabling Gemini to reference the document when answering or generating code.</p><p><a href="https://ai.google.dev/gemini-api/docs?hl=en">Learn more about Gemini CLI context configuration</a></p><h3 id="trae" tabindex="-1">Trae <a class="header-anchor" href="#trae" aria-label="Permalink to &quot;Trae&quot;">​</a></h3><p>In Trae, place the <code>LLMs.txt</code> file into the project’s knowledge sources and enable referencing in the settings. This allows Trae to better support ProComponents of Vuents of Vue components when generating or analyzing code.</p><p><a href="https://trae.ai/docs">Learn more about Trae knowledge sources</a></p><h3 id="qoder" tabindex="-1">Qoder <a class="header-anchor" href="#qoder" aria-label="Permalink to &quot;Qoder&quot;">​</a></h3><p>In Qoder, you can add <code>LLMs.txt</code> as an external knowledge file in <code>.qoder/config.yml</code>, or temporarily reference it in a conversation with <code>@docs LLMs.txt</code>, enhancing support for ProComponents of Vuents of Vue components.</p><p><a href="https://docs.qoder.com/">Learn more about Qoder configuration</a></p><h3 id="other-ai-tools" tabindex="-1">Other AI Tools <a class="header-anchor" href="#other-ai-tools" aria-label="Permalink to &quot;Other AI Tools&quot;">​</a></h3><p>Any AI tool that supports LLMs.txt can use these routes to better understand ProComponents of Vuents of Vue. Simply point your tool to any of the routes above.</p>`,27)]]))}});export{c as default};